async function play() {
	var frames = n.length;
	for (var i = 0; i < frames; i++) {
	    const container = document.getElementById("welcome-ascii-container");
if(container) { container.textContent = n[i]; }
	    await new Promise(r => setTimeout(r, 40));
	}
	play();
}
